impl StreamingToolCallParser {
    /// Flush remaining buffered content. Call this when the stream ends.
    pub fn flush(&mut self) -> Vec<StreamEvent> {
        let mut events = Vec::new();

        if self.inside_tool_call {
            // Incomplete tool call -- emit whatever we have as partial
            self.tool_call_buffer.push_str(&self.buffer);
            if !self.tool_call_buffer.is_empty() {
                events.push(StreamEvent::ToolCallPartial(
                    self.tool_call_buffer.clone(),
                ));
            }
        } else if !self.buffer.is_empty() {
            // Regular text that was held back for partial-tag checking
            events.push(StreamEvent::Text(self.buffer.clone()));
        }

        // Reset all state
        self.buffer.clear();
        self.tool_call_buffer.clear();
        self.inside_tool_call = false;

        events
    }
}
```

Test it:
```rust
#[test]
fn test_flush_incomplete_tool_call() {
    let mut parser = StreamingToolCallParser::new();
    let _ = parser.feed("<tool_call>\n<function=bash>");
    let events = parser.flush();

    let has_partial = events.iter().any(|e| matches!(e, StreamEvent::ToolCallPartial(_)));
    assert!(has_partial, "should emit partial on flush for incomplete tool call");
}

#[test]
fn test_flush_plain_text() {
    let mut parser = StreamingToolCallParser::new();
    let events = parser.feed("Hello, world!");
    let mut all = events;
    all.extend(parser.flush());

    let texts: Vec<String> = all.iter()
        .filter_map(|e| match e { StreamEvent::Text(t) => Some(t.clone()), _ => None })
        .collect();
    assert_eq!(texts.join(""), "Hello, world!");
}
```

Key design: `flush()` is idempotent -- calling it twice produces an empty vec the second time because state is reset.

Use `.peekable()` on any iterator to get a `Peekable` that supports `.peek()` without consuming the element.

```rust
fn split_compound_command(cmd: &str) -> Vec<String> {
    let mut segments = Vec::new();
    let mut current = String::new();
    let mut chars = cmd.chars().peekable();
    let mut in_single_quote = false;
    let mut in_double_quote = false;

    while let Some(c) = chars.next() {
        match c {
            '\'' if !in_double_quote => {
                in_single_quote = !in_single_quote;
                current.push(c);
            }
            '"' if !in_single_quote => {
                in_double_quote = !in_double_quote;
                current.push(c);
            }
            '&' if !in_single_quote && !in_double_quote => {
                // Peek to distinguish & from &&
                if chars.peek() == Some(&'&') {
                    chars.next(); // consume second &
                    segments.push(current.clone());
                    current.clear();
                } else {
                    current.push(c); // background operator, not &&
                }
            }
            '|' if !in_single_quote && !in_double_quote => {
                if chars.peek() == Some(&'|') {
                    chars.next(); // consume second |
                }
                segments.push(current.clone());
                current.clear();
            }
            ';' if !in_single_quote && !in_double_quote => {
                segments.push(current.clone());
                current.clear();
            }
            _ => current.push(c),
        }
    }

    if !current.trim().is_empty() {
        segments.push(current);
    }
    segments
}
```

`chars.peek() == Some(&'&')` checks the next character without consuming it. If it matches, `chars.next()` consumes it. This two-character lookahead pattern is essential for parsing `&&` vs `&`, `||` vs `|`, etc.

Split tool execution into two categories: read-only tools that can run concurrently, and mutating tools that must run serially.

```rust
impl ToolRegistry {
    /// Returns true if this tool is read-only (safe for concurrent execution).
    pub fn is_read_only(tool_name: &str) -> bool {
        matches!(
            tool_name,
            "file_read" | "grep" | "glob" | "web_fetch"
                | "ask_user" | "memory_read" | "research"
                | "request_permissions"
        )
    }
}
```

In the agent loop, batch read-only calls:
```rust
async fn execute_tool_calls(
    calls: Vec<ToolCall>,
    registry: &ToolRegistry,
    ctx: &ToolContext,
) -> Vec<(String, Result<ToolResult>)> {
    let (reads, writes): (Vec<_>, Vec<_>) = calls
        .into_iter()
        .partition(|tc| ToolRegistry::is_read_only(&tc.name));

    // Run all read-only tools concurrently
    let read_futures: Vec<_> = reads.iter().map(|tc| {
        let id = tc.id.clone();
        async move {
            let result = registry.execute(&tc.name, tc.arguments.clone(), ctx).await;
            (id, result)
        }
    }).collect();
    let mut results = futures::future::join_all(read_futures).await;

    // Run write tools serially
    for tc in writes {
        let result = registry.execute(&tc.name, tc.arguments.clone(), ctx).await;
        results.push((tc.id.clone(), result));
    }

    results
}
```

Test both paths:
```rust
