fn test_is_read_only_false_for_mutating_tools() {
    assert!(!ToolRegistry::is_read_only("file_write"));
    assert!(!ToolRegistry::is_read_only("bash"));
}
```

Chain strategies in order of lightest fix to heaviest, returning on first success.

```rust
pub enum RecoveryResult {
    Parsed(Vec<ParsedToolCall>),
    Failed { attempts: Vec<String>, original: String },
}

pub struct RecoveryPipeline {
    adapter: Box<dyn ToolCallAdapter>,
}

impl RecoveryPipeline {
    pub fn new(adapter: Box<dyn ToolCallAdapter>) -> Self {
        Self { adapter }
    }

    pub fn attempt_parse(&self, raw: &str) -> RecoveryResult {
        let mut attempts = Vec::new();

        // Strategy 1: Parse as-is
        if let Some(calls) = self.try_parse(raw) {
            return RecoveryResult::Parsed(calls);
        }
        attempts.push("direct parse".into());

        // Strategy 2: Close unclosed tags
        let repaired = self.close_unclosed_tags(raw);
        if let Some(calls) = self.try_parse(&repaired) {
            return RecoveryResult::Parsed(calls);
        }
        attempts.push("close unclosed tags".into());

        // Strategy 3: Strip surrounding text, extract XML block
        let extracted = self.extract_xml_block(raw);
        if let Some(calls) = self.try_parse(&extracted) {
            return RecoveryResult::Parsed(calls);
        }
        attempts.push("extract XML block".into());

        RecoveryResult::Failed {
            attempts,
            original: raw.to_string(),
        }
    }
}
```

