```

Prefer string checking for integration tests (less brittle), type matching for unit tests where you control the error type.

Spawn the cancellation on a timer, run the tool, and verify it returns a cancellation error.

```rust
#[cfg(unix)]
#[tokio::test]
async fn test_bash_tool_cancel_mid_execution() {
    use crate::tools::bash::BashTool;

    let tool = BashTool::new();
    let cancel = CancelToken::new();
    let (tx, mut rx) = mpsc::channel(64);
    let ctx = ToolContext {
        cwd: PathBuf::from("/tmp"),
        project_path: PathBuf::from("/tmp"),
    };

    // Spawn cancellation after 100ms
    let cancel_clone_rx = cancel.clone_receiver();
    let cancel_sender = CancelToken {
        sender: cancel.sender.clone(),
        receiver: cancel_clone_rx,
    };
    tokio::spawn(async move {
        tokio::time::sleep(std::time::Duration::from_millis(100)).await;
        cancel_sender.cancel();
    });

    // Execute a long-running command
    let result = tool
        .execute_with_cancel(
            json!({"command": "sleep 10"}),
            &ctx,
            &cancel,
            Some(tx),
        )
        .await
        .unwrap();

    // Should have been cancelled
    assert!(result.is_error);
    assert!(
        result.output.contains("Cancelled"),
        "expected cancel message, got: {}",
        result.output
    );

    // Drain progress channel
    rx.close();
}
```

Key elements:
- `#[cfg(unix)]` -- process signals work differently on Windows
- `sleep 10` is the victim command -- long enough that cancellation fires first
- 100ms delay before cancel -- gives the command time to start
- Assert both `is_error` and the message content
- `rx.close()` prevents the sender from blocking if it tries to send after test ends

Use `fold` with an initial value and a combining function.

```rust
// Instead of a manual loop:
fn classify_bash_imperative(params: &Value) -> PermissionTier {
    let segments = split_compound_command(command);
    let mut worst = PermissionTier::Safe;
    for segment in &segments {
        let tier = classify_single_bash(segment);
        worst = worse_tier(worst, tier);
    }
    worst
}

// Use fold:
fn classify_bash(params: &Value) -> PermissionTier {
    let command = params.get("command").and_then(|v| v.as_str()).unwrap_or("");
    split_compound_command(command)
        .iter()
        .map(|s| classify_single_bash(s))
        .fold(PermissionTier::Safe, worse_tier)
}
```

Or if you derived `Ord` on the enum:
```rust
split_compound_command(command)
    .iter()
    .map(|s| classify_single_bash(s))
    .max()
    .unwrap_or(PermissionTier::Safe)
```

`fold` is the general case -- it works with any combining function. `max()` is a specialization for `Ord` types. Both avoid mutable state and express the intent ("find the worst tier") more directly than a for loop.
